app.use(bodyParser.json());

const client = new Client({ node: 'http://localhost:9200' });

app.post('/search', async (req, res) => {
  try {
    const { index, query, script } = req.body;

    if (!index || !query || !script) {
      return res.status(400).send('Index, query, and script are required.');
    }

    // Basic validation to prevent script injection
    if (typeof script !== 'string' || /[^a-zA-Z0-9_+\-*/\s]/.test(script)) {
      return res.status(400).send('Invalid script.');
    }

    const searchQuery = {
      index,
      body: {
        query: {
          script_score: {
            query: {
              match: query
            },
            script: {
              source: script
            }
          }
        }
      }
    };

    const { body } = await client.search(searchQuery);
    res.json(body.hits.hits);
  } catch (error) {
    res.status(500).send(error.toString());
  }
});

